import React, { useRef, useCallback, useEffect } from 'react';
import { Animated, Platform, View, ViewStyle } from 'react-native';
import { useScrollAnim } from '../context/ScrollAnimContext';
interface Props {
  children: React.ReactNode;
  style?: ViewStyle | ViewStyle[];
  delay?: number;
  direction?: 'up' | 'left' | 'right' | 'fade';
}
export default function AnimatedSection({ children, style, delay = 0, direction = 'up' }: Props) {
  const { scrollY, windowHeight } = useScrollAnim();
  const opacity = useRef(new Animated.Value(0)).current;
  const translateY = useRef(new Animated.Value(direction === 'up' ? 48 : 0)).current;
  const translateX = useRef(
    new Animated.Value(direction === 'left' ? -48 : direction === 'right' ? 48 : 0)
  ).current;
  const scale = useRef(new Animated.Value(direction === 'fade' ? 0.92 : 0.96)).current;
  const hasTriggered = useRef(false);
  const viewRef = useRef<View>(null);
  const layoutY = useRef(-1);
  const triggerAnimation = useCallback(() => {
    if (hasTriggered.current) return;
    hasTriggered.current = true;
    setTimeout(() => {
      Animated.parallel([
        Animated.timing(opacity, { toValue: 1, duration: 650, useNativeDriver: true }),
        Animated.spring(translateY, { toValue: 0, tension: 55, friction: 14, useNativeDriver: true }),
        Animated.spring(translateX, { toValue: 0, tension: 55, friction: 14, useNativeDriver: true }),
        Animated.spring(scale, { toValue: 1, tension: 80, friction: 10, useNativeDriver: true }),
      ]).start();
    }, delay);
  }, [delay, opacity, translateY, translateX, scale]);
  // Web: use IntersectionObserver
  useEffect(() => {
    if (Platform.OS !== 'web') return;
    const el = viewRef.current as unknown as Element;
    if (!el) return;
    const observer = new IntersectionObserver(
      ([entry]) => { if (entry.isIntersecting) triggerAnimation(); },
      { threshold: 0.12, rootMargin: '0px 0px -40px 0px' }
    );
    observer.observe(el);
    return () => observer.disconnect();
  }, [triggerAnimation]);
  // Native: use scroll Y listener
  useEffect(() => {
    if (Platform.OS === 'web') return;
    const id = scrollY.addListener(({ value }) => {
      if (layoutY.current < 0) return;
      if (value + windowHeight > layoutY.current + 60) triggerAnimation();
    });
    return () => scrollY.removeListener(id);
  }, [scrollY, windowHeight, triggerAnimation]);
  return (
    <Animated.View
      ref={viewRef as any}
      onLayout={(e) => {
        layoutY.current = e.nativeEvent.layout.y;
        // trigger if already in view (initial render)
        if (layoutY.current < windowHeight * 0.85) triggerAnimation();
      }}
      style={[
        Array.isArray(style) ? Object.assign({}, ...style) : style,
        { opacity, transform: [{ translateY }, { translateX }, { scale }] },
      ]}
    >
      {children}
    </Animated.View>
  );
}

import React, { useRef, useCallback, useEffect } from 'react';
import { Animated, Platform, View, ViewStyle } from 'react-native';
import { useScrollAnim } from '../context/ScrollAnimContext';
interface Props {
  children: React.ReactNode;
  style?: ViewStyle | ViewStyle[];
  delay?: number;
  direction?: 'up' | 'left' | 'right' | 'fade' | 'zoom' | 'down';
}
export default function AnimatedSection({ children, style, delay = 0, direction = 'up' }: Props) {
  const { scrollY, windowHeight } = useScrollAnim();
  const opacity = useRef(new Animated.Value(0)).current;
  const translateY = useRef(new Animated.Value(
    direction === 'up' ? 52 : direction === 'down' ? -52 : 0
  )).current;
  const translateX = useRef(
    new Animated.Value(direction === 'left' ? -52 : direction === 'right' ? 52 : 0)
  ).current;
  const scale = useRef(new Animated.Value(
    direction === 'fade' ? 0.94 : direction === 'zoom' ? 0.7 : 0.96
  )).current;
  const hasTriggered = useRef(false);
  const viewRef = useRef<View>(null);
  const layoutY = useRef(-1);
  const triggerAnimation = useCallback(() => {
    if (hasTriggered.current) return;
    hasTriggered.current = true;
    setTimeout(() => {
      Animated.parallel([
        Animated.timing(opacity, { toValue: 1, duration: 680, useNativeDriver: true }),
        Animated.spring(translateY, { toValue: 0, tension: 50, friction: 13, useNativeDriver: true }),
        Animated.spring(translateX, { toValue: 0, tension: 50, friction: 13, useNativeDriver: true }),
        direction === 'zoom'
          ? Animated.spring(scale, { toValue: 1, tension: 65, friction: 9, useNativeDriver: true })
          : Animated.spring(scale, { toValue: 1, tension: 80, friction: 10, useNativeDriver: true }),
      ]).start();
    }, delay);
  }, [delay, opacity, translateY, translateX, scale, direction]);
  // Web: use IntersectionObserver
  useEffect(() => {
    if (Platform.OS !== 'web') return;
    const el = viewRef.current as unknown as Element;
    if (!el) return;
    const observer = new IntersectionObserver(
      ([entry]) => { if (entry.isIntersecting) triggerAnimation(); },
      { threshold: 0.10, rootMargin: '0px 0px -36px 0px' }
    );
    observer.observe(el);
    return () => observer.disconnect();
  }, [triggerAnimation]);
  // Native: use scroll Y listener
  useEffect(() => {
    if (Platform.OS === 'web') return;
    const id = scrollY.addListener(({ value }) => {
      if (layoutY.current < 0) return;
      if (value + windowHeight > layoutY.current + 60) triggerAnimation();
    });
    return () => scrollY.removeListener(id);
  }, [scrollY, windowHeight, triggerAnimation]);
  return (
    <Animated.View
      ref={viewRef as any}
      onLayout={(e) => {
        layoutY.current = e.nativeEvent.layout.y;
        // trigger if already in view (initial render)
        if (layoutY.current < windowHeight * 0.85) triggerAnimation();
      }}
      style={[
        Array.isArray(style) ? Object.assign({}, ...style) : style,
        { opacity, transform: [{ translateY }, { translateX }, { scale }] },
      ]}
    >
      {children}
    </Animated.View>
  );
}

import React, { useEffect, useRef, useState, useCallback } from 'react';
import {
  Animated, Platform, Pressable, SafeAreaView, ScrollView,
  StyleSheet, Text, View, useWindowDimensions,
} from 'react-native';
import { StatusBar } from 'expo-status-bar';
import { LinearGradient } from 'expo-linear-gradient';
import { injectGlobalStyles } from './utils/webStyles';
import { ScrollAnimProvider } from './context/ScrollAnimContext';
import CursorGlow from './components/CursorGlow';
import Navbar from './components/Navbar';
import ScrollProgress from './components/ScrollProgress';
import MarqueeBanner from './components/MarqueeBanner';
import HeroSection from './components/HeroSection';
import AboutSection from './components/AboutSection';
import ProjectsSection from './components/ProjectsSection';
import SkillsSection from './components/SkillsSection';
import ExperienceSection from './components/ExperienceSection';
import EducationSection from './components/EducationSection';
import ContactSection from './components/ContactSection';
import FooterSection from './components/FooterSection';

// Section definitions for dot navigation
const SECTIONS = [
  { key: 'hero',       label: 'Home',       color: '#818CF8' },
  { key: 'about',      label: 'About',      color: '#38BDF8' },
  { key: 'projects',   label: 'Projects',   color: '#A78BFA' },
  { key: 'skills',     label: 'Skills',     color: '#34D399' },
  { key: 'experience', label: 'Experience', color: '#FB7185' },
  { key: 'education',  label: 'Education',  color: '#FBBF24' },
  { key: 'contact',    label: 'Contact',    color: '#F472B6' },
];

// Floating right-side dot navigator (web only)
function DotNav({
  active, onPress, sections,
}: {
  active: string;
  onPress: (s: string) => void;
  sections: typeof SECTIONS;
}) {
  if (Platform.OS !== 'web') return null;
  return (
    <View style={dotStyles.wrap}>
      {sections.map((s) => {
        const isActive = active === s.key;
        return (
          <Pressable key={s.key} onPress={() => onPress(s.key)} style={dotStyles.dot} hitSlop={8}>
            <View style={[
              dotStyles.dotInner,
              isActive
                ? { width: 10, height: 10, backgroundColor: s.color, borderRadius: 5 }
                : { width: 6, height: 6, backgroundColor: 'rgba(255,255,255,0.2)', borderRadius: 3 },
              Platform.OS === 'web' ? ({ transition: 'all 0.3s' } as any) : {},
            ]} />
            {isActive && (
              <Text style={[dotStyles.label, { color: s.color }]}>{s.label}</Text>
            )}
          </Pressable>
        );
      })}
    </View>
  );
}

// Gradient transition divider between sections
function SectionDivider({ flip = false }: { flip?: boolean }) {
  return (
    <View style={divStyles.wrap} pointerEvents="none">
      <LinearGradient
        colors={flip
          ? ['transparent', 'rgba(99,102,241,0.06)', 'rgba(56,189,248,0.04)', 'transparent']
          : ['transparent', 'rgba(56,189,248,0.04)', 'rgba(99,102,241,0.06)', 'transparent']}
        style={divStyles.grad}
        start={{ x: 0, y: 0 }} end={{ x: 1, y: 0 }}
      />
    </View>
  );
}

export default function App() {
  const { height: windowHeight, width: windowWidth } = useWindowDimensions();
  const scrollViewRef = useRef<ScrollView>(null);
  const scrollY = useRef(new Animated.Value(0)).current;
  const sectionOffsets = useRef<Record<string, number>>({});
  const [contentHeight, setContentHeight] = useState(0);
  const [activeSection, setActiveSection] = useState('hero');

  // Inject global CSS & launch cursor glow on web
  useEffect(() => { injectGlobalStyles(); }, []);

  const handleScroll = Animated.event(
    [{ nativeEvent: { contentOffset: { y: scrollY } } }],
    {
      useNativeDriver: false,
      listener: (e: any) => {
        const y = e.nativeEvent.contentOffset.y;
        // Determine active section
        const offsets = sectionOffsets.current;
        let current = 'hero';
        for (const s of SECTIONS) {
          if (offsets[s.key] !== undefined && y + windowHeight * 0.4 >= offsets[s.key]) {
            current = s.key;
          }
        }
        setActiveSection(current);
      },
    }
  );

  const scrollToSection = useCallback((section: string) => {    const y = sectionOffsets.current[section];
    if (y !== undefined) {
      scrollViewRef.current?.scrollTo({ y: Math.max(0, y - 72), animated: true });
    }
  }, []);

  const registerSection = (section: string) => (event: any) => {
    sectionOffsets.current[section] = event.nativeEvent.layout.y;
  };

  const isWide = windowWidth >= 900;

  return (
    <ScrollAnimProvider windowHeight={windowHeight} scrollY={scrollY}>
      <SafeAreaView style={styles.safeArea}>
        <StatusBar style="light" />

        {/* Web-only: cursor glow effect */}
        <CursorGlow />

        <Navbar scrollY={scrollY} onNavPress={scrollToSection} />
        <ScrollProgress scrollY={scrollY} contentHeight={contentHeight} windowHeight={windowHeight} />

        {/* Floating dot navigator */}
        <DotNav active={activeSection} onPress={scrollToSection} sections={SECTIONS} />

        <ScrollView
          ref={scrollViewRef}
          id="scroll-root"
          style={[styles.scroll, Platform.OS === 'web' ? ({ overflowY: 'scroll' } as any) : {}]}
          contentContainerStyle={styles.content}
          scrollEventThrottle={16}
          onScroll={handleScroll}
          onContentSizeChange={(_, h) => setContentHeight(h)}
          showsVerticalScrollIndicator={false}
        >
          {/* ── HERO (full screen) ───────────────────── */}
          <View
            onLayout={registerSection('hero')}
            style={[styles.sectionFull, { minHeight: windowHeight }]}
          >
            <HeroSection />
          </View>

          {/* Marquee connector */}
          <MarqueeBanner />

          {/* ── ABOUT ───────────────────────────────── */}
          <SectionDivider />
          <View onLayout={registerSection('about')} style={styles.sectionBlock}>
            <AboutSection />
          </View>

          {/* ── PROJECTS ────────────────────────────── */}
          <SectionDivider flip />
          <View onLayout={registerSection('projects')} style={styles.sectionBlock}>
            <ProjectsSection />
          </View>

          {/* ── SKILLS ──────────────────────────────── */}
          <SectionDivider />
          <View onLayout={registerSection('skills')} style={styles.sectionBlock}>
            <SkillsSection />
          </View>

          {/* ── EXPERIENCE ──────────────────────────── */}
          <SectionDivider flip />
          <View onLayout={registerSection('experience')} style={styles.sectionBlock}>
            <ExperienceSection />
          </View>

          {/* ── EDUCATION ───────────────────────────── */}
          <SectionDivider />
          <View onLayout={registerSection('education')} style={styles.sectionBlock}>
            <EducationSection />
          </View>

          {/* ── CONTACT (full screen CTA) ────────────── */}
          <SectionDivider flip />
          <View onLayout={registerSection('contact')} style={[styles.sectionFull, { minHeight: windowHeight * 0.75 }]}>
            <ContactSection />
          </View>

          <FooterSection />
        </ScrollView>
      </SafeAreaView>
    </ScrollAnimProvider>
  );
}

const styles = StyleSheet.create({
  safeArea: { flex: 1, backgroundColor: '#000' },
  scroll: {
    flex: 1,
    backgroundColor: '#000',
    ...(Platform.OS === 'web' ? { marginTop: 64 } as any : {}),
  },
  content: { paddingBottom: 0 },
  // Full-viewport section (Hero, Contact)
  sectionFull: {
    justifyContent: 'center',
    overflow: 'hidden',
  },
  // Content sections with generous Apple-style vertical breathing room
  sectionBlock: {
    paddingVertical: Platform.OS === 'web' ? 40 : 0,
  },
});

// Dot nav styles
const dotStyles = StyleSheet.create({
  wrap: {
    position: 'absolute',
    right: 24,
    top: '50%',
    zIndex: 500,
    gap: 14,
    alignItems: 'center',
    ...(Platform.OS === 'web' ? ({ transform: 'translateY(-50%)' } as any) : {}),
  },
  dot: { alignItems: 'center', justifyContent: 'center', flexDirection: 'row', gap: 8 },
  dotInner: {},
  label: { fontSize: 11, fontWeight: '700', letterSpacing: 0.5 },
});

// Divider styles
const divStyles = StyleSheet.create({
  wrap: { height: 1, overflow: 'visible' },
  grad: { height: 1, width: '100%' },
});

