import React, { useEffect, useRef, useState } from 'react';
import {
  Animated, Easing, Linking, Platform, Pressable,
  StyleSheet, Text, View, useWindowDimensions,
} from 'react-native';
import { LinearGradient } from 'expo-linear-gradient';
import { COLORS, GRADIENTS, RADIUS } from '../constants/theme';
import { PROFILE, CONTACT } from '../constants/data';
import ProfileAvatar from './ProfileAvatar';
import TypeWriter from './TypeWriter';
const TYPEWRITER_TEXTS = [
  'System Analyst',
  'Web Developer',
  'Database Architect',
  'IT Problem Solver',
  'Automation Engineer',
];
export default function HeroSection() {
  const { width } = useWindowDimensions();
  const isWide = width >= 900;
  const badgeFade    = useRef(new Animated.Value(0)).current;
  const nameFade     = useRef(new Animated.Value(0)).current;
  const nameSlide    = useRef(new Animated.Value(-50)).current;
  const twFade       = useRef(new Animated.Value(0)).current;
  const twSlide      = useRef(new Animated.Value(20)).current;
  const descFade     = useRef(new Animated.Value(0)).current;
  const btnFade      = useRef(new Animated.Value(0)).current;
  const btnScale     = useRef(new Animated.Value(0.8)).current;
  const statsFade    = useRef(new Animated.Value(0)).current;
  const avatarFade   = useRef(new Animated.Value(0)).current;
  const avatarSlide  = useRef(new Animated.Value(70)).current;
  useEffect(() => {
    Animated.stagger(130, [
      Animated.timing(badgeFade, { toValue: 1, duration: 500, easing: Easing.out(Easing.quad), useNativeDriver: true }),
      Animated.parallel([
        Animated.timing(nameFade, { toValue: 1, duration: 800, easing: Easing.out(Easing.cubic), useNativeDriver: true }),
        Animated.spring(nameSlide, { toValue: 0, tension: 50, friction: 14, useNativeDriver: true }),
      ]),
      Animated.parallel([
        Animated.timing(twFade, { toValue: 1, duration: 600, useNativeDriver: true }),
        Animated.spring(twSlide, { toValue: 0, tension: 55, friction: 14, useNativeDriver: true }),
      ]),
      Animated.timing(descFade, { toValue: 1, duration: 700, useNativeDriver: true }),
      Animated.parallel([
        Animated.timing(btnFade, { toValue: 1, duration: 500, useNativeDriver: true }),
