    @keyframes ct-word-reveal {
      from { opacity: 0; transform: translateY(24px); filter: blur(4px); }
      to   { opacity: 1; transform: translateY(0);    filter: blur(0); }
    }
  `;
  document.head.appendChild(s);
}
